SELECT h.*, ste.site_nm AS site_nm, dli.member_nm AS dliv_nm, ord.member_nm AS order_nm, usr.user_nm AS chg_user_nm, cd_ds.code_label AS dliv_status_cd_nm FROM odh_dliv_status_hist h LEFT JOIN sy_site ste ON ste.site_id = h.site_id LEFT JOIN od_dliv dli ON dli.dliv_id = h.dliv_id LEFT JOIN od_order ord ON ord.order_id = h.order_id LEFT JOIN sy_user usr ON usr.user_id = h.chg_user_id LEFT JOIN sy_code cd_ds ON cd_ds.code_grp = 'DLIV_STATUS' AND cd_ds.code_value = h.dliv_status_cd
ORDER BY h.dliv_status_hist_id ASC ORDER BY h.dliv_status_hist_id DESC ORDER BY h.reg_date ASC ORDER BY h.reg_date DESC ORDER BY h.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

